public int getMaxOccurrences(String text, String pattern) {
    int[] count = new int[2];
    for (char c : text.toCharArray()) {
        if (c == pattern.charAt(1)) {
            count[1] += count[0];
        }
        else if (c == pattern.charAt(0)) {
            count[0] += 1;
        }
    }
    return count[1];
}
```

